  spend(_datum, _redeemer, _own_ref, self) {
    let sum_inputs =
      list.foldl(
        self.inputs,
        0,
        fn(inp, acc) { acc + assets.lovelace_of(inp.output.value) },
      )
    let sum_outputs =
      list.foldl(
        self.outputs,
        0,
        fn(o, acc) { acc + assets.lovelace_of(o.value) },
      )
    sum_inputs == sum_outputs
  }
}

