use cardano/transaction

pub type Datum {
  owner: VerificationKeyHash,
}

pub type Redeemer {
  Update
  Close
}

validator managed_utxo {
  spend(datum: Option<Datum>, redeemer: Redeemer, own_ref, self) {
    expect Some(Datum { owner }) = datum
    let signed = list.has(self.extra_signatories, owner)
    when redeemer is {
      Update -> signed
      Close -> {
        let own_input = transaction.resolve_input(self.inputs, own_ref)
        let script_addr = own_input.output.address
        let no_continuation =
          list.all(self.outputs, fn(o) { o.address != script_addr })
        signed && no_continuation
      }
    }
  }
}

