use cardano/assets
use cardano/transaction

validator token_floor(policy_id: ByteArray, asset_name: ByteArray) {
  spend(_datum, _redeemer, own_ref, self) {
    let own_input = transaction.resolve_input(self.inputs, own_ref)
    assets.quantity_of(own_input.output.value, policy_id, asset_name) >= 5
  }
}

Using `list.head(self.inputs)` inside a spend handler is unsafe. It returns the first input in the transaction, which may not be the UTxO currently governed by this validator. In a transaction with multiple inputs, any of them could be first, and an attacker can order inputs to put a different UTxO at the head of the list.

The correct pattern uses the `own_ref` argument provided by the spend handler, which always identifies the exact input being validated:

```aiken
use cardano/transaction

validator my_validator {
  spend(_datum, _redeemer, own_ref, self) {
    let own_input = transaction.resolve_input(self.inputs, own_ref)
    // use own_input.output safely
    True
  }
}
```

