use aiken/collection/list
use cardano/assets

validator lovelace_not_inflated {
  spend(_datum, _redeemer, _own_ref, self) {
    let sum_lovelace = fn(acc, item) {
      acc + assets.lovelace_of(item.output.value)
    }
    let input_ada = list.foldl(self.inputs, 0, sum_lovelace)
    let output_ada =
      list.foldl(
        self.outputs,
        0,
        fn(acc, o) { acc + assets.lovelace_of(o.value) },
      )
    output_ada <= input_ada
  }
}

