use cardano/assets

pub type CapDatum {
  supply_cap: Int,
}

validator capped_mint(cap_policy: ByteArray) {
  mint(_redeemer, policy_id, self) {
    expect Some(ref_input) =
      list.find(
        self.reference_inputs,
        fn(i) { assets.quantity_of(i.output.value, cap_policy, "") >= 1 },
      )
    expect Some(CapDatum { supply_cap }) = ref_input.output.datum
    let minted = assets.quantity_of(self.mint, policy_id, "")
    supply_cap > 0 && minted > 0 && minted <= supply_cap
  }
}
